import { jwtVerify } from "jose";
import { ZuploContext, ZuploRequest } from "@zuplo/runtime";

type JwtAuthOptions = {
  secret: string;
};

type JwtPayload = {
  sub?: string;
  plan?: string;
  [key: string]: unknown;
};

export default async function (
  request: ZuploRequest,
  _context: ZuploContext,
  options: JwtAuthOptions
) {
  const authHeader = request.headers.get("authorization");
  if (!authHeader || !authHeader.toLowerCase().startsWith("bearer ")) {
    return new Response("Unauthorized", { status: 401 });
  }

  const token = authHeader.slice("bearer ".length).trim();
  if (!token) {
    return new Response("Unauthorized", { status: 401 });
  }

  try {
    const secret = new TextEncoder().encode(options.secret);
    const { payload } = await jwtVerify(token, secret, {
      algorithms: ["HS256"]
    });

    const typedPayload = payload as JwtPayload;
    if (!typedPayload.sub) {
      return new Response("Unauthorized", { status: 401 });
    }

    request.user = {
      sub: String(typedPayload.sub),
      data: typedPayload
    };

    return request;
  } catch (_error) {
    return new Response("Unauthorized", { status: 401 });
  }
}

import {
  CustomRateLimitDetails,
  ZuploContext,
  ZuploRequest
} from "@zuplo/runtime";

export function rateLimit(
  request: ZuploRequest,
  _context: ZuploContext,
  _policyName: string
): CustomRateLimitDetails | undefined {
  const user = request.user;
  if (!user?.sub) {
    return undefined;
  }

  const plan = (user.data as { plan?: string } | undefined)?.plan;
  const requestsAllowed = plan === "pro" ? 5 : 2;

  return {
    key: user.sub,
    requestsAllowed,
    timeWindowMinutes: 1
  };
}
